package github.chains;

import spoon.Launcher;
import spoon.reflect.code.CtConstructorCall;
import spoon.reflect.declaration.CtClass;
import spoon.reflect.declaration.CtElement;
import spoon.reflect.declaration.CtMethod;
import spoon.reflect.declaration.CtType;
import spoon.reflect.reference.CtTypeReference;
import spoon.reflect.visitor.filter.TypeFilter;

import java.io.File;
import java.util.List;

/**
 * Generic transformation rule to fix TSerializer constructor changes in libthrift 0.16.0
 * This transformation handles the breaking change where TSerializer constructors now throw TTransportException
 */
public class Main {
    public static void main(String[] args) {
        if (args.length < 1) {
            System.err.println("Usage: java Main <source_directory>");
            System.exit(1);
        }

        String sourceDirectory = args[0];

        Launcher launcher = new Launcher();
        launcher.addInputResource(sourceDirectory);
        launcher.setSourceOutputDirectory(sourceDirectory + "/processed");
        launcher.getEnvironment().setNoClasspath(true);

        CtModel model = launcher.buildModel();

        // Find all TSerializer constructor calls
        List<CtConstructorCall> serializerConstructors = model.getElements(new TypeFilter<>(CtConstructorCall.class) {
            @Override
            public boolean matches(CtConstructorCall element) {
                CtTypeReference<?> typeRef = element.getType();
                if (typeRef == null) return false;
                return "org.apache.thrift.TSerializer".equals(typeRef.getQualifiedName());
            }
        });

        for (CtConstructorCall constructorCall : serializerConstructors) {
            // Check if the constructor is inside a method that doesn't declare TTransportException
            CtMethod<?> parentMethod = constructorCall.getParent(CtMethod.class);

            if (parentMethod != null) {
                // Add throws declaration for TTransportException if not already present
                boolean hasTTransportException = false;
                for (CtTypeReference<?> thrown : parentMethod.getThrownTypes()) {
                    if ("org.apache.thrift.transport.TTransportException".equals(thrown.getQualifiedName())) {
                        hasTTransportException = true;
                        break;
                    }
                }

                if (!hasTTransportException) {
                    // Add the exception to the method's throws clause
                    CtTypeReference<?> tTransportExceptionRef = 
                        launcher.getFactory().Type().createReference("org.apache.thrift.transport.TTransportException");
                    parentMethod.addThrownType(tTransportExceptionRef);
                }

                // If the constructor call is part of a field initialization, we also need to make sure
                // it's properly handled in the constructor or initialization block
                if (constructorCall.getParent(CtElement.class) instanceof CtField) {
                    // This is a field initialization, which should be fine as long as the method 
                    // that initializes it throws TTransportException
                }
            }
        }

        // Generate the updated source code
        launcher.setSourceOutputDirectory(sourceDirectory + "/processed");
        launcher.process();

        System.out.println("Transformation completed. Check " + sourceDirectory + "/processed for results.");
    }
}

